```typescript
export type InvoiceState =
  | { status: "empty" }
  | { status: "draft"; id: string; amount: number }
  | { status: "issued"; id: string; amount: number; issuedAt: string };

export type InvoiceCommand =
  | { type: "create"; id: string; amount: number }
  | { type: "issue"; at: string };

export type InvoiceEvent =
  | { type: "InvoiceDrafted"; id: string; amount: number }
  | { type: "InvoiceIssued"; at: string };

export class DomainError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "DomainError";
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const invoiceDecider: Decider<InvoiceCommand, InvoiceEvent, InvoiceState> = {
  initialState: { status: "empty" },
  decide(command, state) {
    switch (command.type) {
      case "create": {
        if (state.status !== "empty") throw new DomainError("INVOICE_EXISTS");
        if (command.amount <= 0) throw new DomainError("AMOUNT_INVALID");
        return [{ type: "InvoiceDrafted", id: command.id, amount: command.amount }];
      }
      case "issue": {
        if (state.status !== "draft") throw new DomainError("NOT_DRAFT");
        return [{ type: "InvoiceIssued", at: command.at }];
      }
      default: {
        const _never: never = command;
        throw new DomainError("UNKNOWN_COMMAND");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "InvoiceDrafted":
        return { status: "draft", id: event.id, amount: event.amount };
      case "InvoiceIssued":
        if (state.status !== "draft") return state;
        return { status: "issued", id: state.id, amount: state.amount, issuedAt: event.at };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};

export function when(state: InvoiceState, event: InvoiceEvent): InvoiceState {
  return invoiceDecider.evolve(state, event);
}

export function aggregateStream<A, E>(
  events: E[],
  reducer: (state: A, event: E) => A,
  initial: A,
): A {
  return events.reduce(reducer, initial);
}
