```typescript
export type ReservationState =
  | { status: "none" }
  | { status: "pending"; id: string; guests: number }
  | { status: "confirmed"; id: string; guests: number; confirmedAt: string }
  | { status: "cancelled"; id: string };

export type ReservationCommand =
  | { type: "create"; id: string; guests: number }
  | { type: "confirm"; at: string }
  | { type: "cancel"; reason: string };

export type ReservationEvent =
  | { type: "ReservationCreated"; id: string; guests: number }
  | { type: "ReservationConfirmed"; at: string }
  | { type: "ReservationCancelled"; reason: string };

export class ReservationError extends Error {
  constructor(code: string) { super(code); this.name = "ReservationError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const reservationDecider: Decider<ReservationCommand, ReservationEvent, ReservationState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "create":
        if (state.status !== "none") throw new ReservationError("ALREADY_EXISTS");
        if (command.guests <= 0) throw new ReservationError("INVALID_GUESTS");
        return [{ type: "ReservationCreated", id: command.id, guests: command.guests }];
      case "confirm":
        if (state.status === "cancelled") throw new ReservationError("CANCELLED");
        if (state.status !== "pending") throw new ReservationError("NOT_PENDING");
        return [{ type: "ReservationConfirmed", at: command.at }];
      case "cancel":
        if (state.status === "cancelled") return [];
        if (state.status === "none") throw new ReservationError("NOT_FOUND");
        return [{ type: "ReservationCancelled", reason: command.reason }];
      default: {
        const _n: never = command;
        throw new ReservationError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "ReservationCreated":
        return { status: "pending", id: event.id, guests: event.guests };
      case "ReservationConfirmed":
        if (state.status !== "pending") return state;
        return { status: "confirmed", id: state.id, guests: state.guests, confirmedAt: event.at };
      case "ReservationCancelled":
        if (state.status === "none") return state;
        return { status: "cancelled", id: "id" in state ? state.id : "" };
      default: {
        const _n: never = event;
        return state;
      }
    }
  },
};
```

A Decider is a pure triple (initialState, decide, evolve). `decide` consumes a command and current state, producing events or throwing on invariant violations. `evolve` folds events into state. No I/O, so it is trivially testable and deterministic.

```typescript
export type ShipmentState =
  | { status: "created"; id: string }
  | { status: "dispatched"; id: string; carrier: string }
  | { status: "delivered"; id: string; carrier: string; at: string }
  | { status: "failed"; id: string; reason: string };

export type ShipmentCommand =
  | { type: "dispatch"; carrier: string }
  | { type: "deliver"; at: string }
  | { type: "fail"; reason: string };

export type ShipmentEvent =
  | { type: "ShipmentDispatched"; carrier: string }
  | { type: "ShipmentDelivered"; at: string }
  | { type: "ShipmentFailed"; reason: string };

export class ShipmentError extends Error {}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const shipmentDecider = (id: string): Decider<ShipmentCommand, ShipmentEvent, ShipmentState> => ({
  initialState: { status: "created", id },
  decide(c, s) {
    switch (c.type) {
      case "dispatch":
        if (s.status !== "created") throw new ShipmentError("NOT_CREATED");
        return [{ type: "ShipmentDispatched", carrier: c.carrier }];
      case "deliver":
        if (s.status !== "dispatched") throw new ShipmentError("NOT_DISPATCHED");
        return [{ type: "ShipmentDelivered", at: c.at }];
      case "fail":
        if (s.status === "delivered") throw new ShipmentError("ALREADY_DELIVERED");
        return [{ type: "ShipmentFailed", reason: c.reason }];
      default: { const _n: never = c; throw new ShipmentError("UNKNOWN"); }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "ShipmentDispatched":
        if (s.status !== "created") return s;
        return { status: "dispatched", id: s.id, carrier: e.carrier };
      case "ShipmentDelivered":
        if (s.status !== "dispatched") return s;
        return { status: "delivered", id: s.id, carrier: s.carrier, at: e.at };
      case "ShipmentFailed":
        return { status: "failed", id: "id" in s ? s.id : "", reason: e.reason };
      default: { const _n: never = e; return s; }
    }
  },
});
