```typescript
export type GuestStayState =
  | { status: "none" }
  | { status: "in"; id: string; guest: string; nights: number }
  | { status: "out"; id: string; totalNights: number };

export type GuestStayCommand =
  | { type: "checkIn"; id: string; guest: string }
  | { type: "chargeNight" }
  | { type: "checkOut" };

export type GuestStayEvent =
  | { type: "GuestCheckedIn"; id: string; guest: string }
  | { type: "NightCharged" }
  | { type: "GuestCheckedOut"; totalNights: number };

export class StayError extends Error {}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const stayDecider: Decider<GuestStayCommand, GuestStayEvent, GuestStayState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "checkIn":
        if (state.status !== "none") throw new StayError("ALREADY_CHECKED_IN");
        return [{ type: "GuestCheckedIn", id: command.id, guest: command.guest }];
      case "chargeNight":
        if (state.status !== "in") throw new StayError("NOT_CHECKED_IN");
        return [{ type: "NightCharged" }];
      case "checkOut":
        if (state.status !== "in") throw new StayError("NOT_CHECKED_IN");
        if (state.nights < 1) throw new StayError("NO_NIGHTS_CHARGED");
        return [{ type: "GuestCheckedOut", totalNights: state.nights }];
      default: { const _n: never = command; throw new StayError("UNKNOWN"); }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "GuestCheckedIn":
        return { status: "in", id: event.id, guest: event.guest, nights: 0 };
      case "NightCharged":
        if (state.status !== "in") return state;
        return { ...state, nights: state.nights + 1 };
      case "GuestCheckedOut":
        if (state.status !== "in") return state;
        return { status: "out", id: state.id, totalNights: event.totalNights };
      default: { const _n: never = event; return state; }
    }
  },
};

export function when(state: GuestStayState, event: GuestStayEvent): GuestStayState {
  return stayDecider.evolve(state, event);
}

export function aggregateStream<A, E>(
  events: E[],
  reducer: (state: A, event: E) => A,
  initial: A,
): A {
  return events.reduce(reducer, initial);
}

export function stayFromEvents(events: GuestStayEvent[]): GuestStayState {
  return aggregateStream(events, when, stayDecider.initialState);
}
```

```typescript
export type SubscriptionState =
  | { status: "none" }
  | { status: "active"; id: string; plan: string; renewals: number }
  | { status: "cancelled"; id: string };

export type SubscriptionCommand =
  | { type: "subscribe"; id: string; plan: string }
  | { type: "renew" }
  | { type: "cancel"; reason: string };

export type SubscriptionEvent =
  | { type: "Subscribed"; id: string; plan: string }
  | { type: "Renewed" }
  | { type: "Cancelled"; reason: string };

export class SubscriptionError extends Error {}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const subscriptionDecider: Decider<SubscriptionCommand, SubscriptionEvent, SubscriptionState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "subscribe":
        if (state.status !== "none") throw new SubscriptionError("EXISTS");
        if (command.plan.length === 0) throw new SubscriptionError("INVALID_PLAN");
        return [{ type: "Subscribed", id: command.id, plan: command.plan }];
      case "renew":
        if (state.status === "cancelled") throw new SubscriptionError("CANCELLED");
        if (state.status !== "active") throw new SubscriptionError("NOT_ACTIVE");
        return [{ type: "Renewed" }];
      case "cancel":
        if (state.status !== "active") throw new SubscriptionError("NOT_ACTIVE");
        return [{ type: "Cancelled", reason: command.reason }];
      default: { const _n: never = command; throw new SubscriptionError("UNKNOWN"); }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "Subscribed":
        return { status: "active", id: event.id, plan: event.plan, renewals: 0 };
      case "Renewed":
        if (state.status !== "active") return state;
        return { ...state, renewals: state.renewals + 1 };
      case "Cancelled":
        if (state.status !== "active") return state;
        return { status: "cancelled", id: state.id };
      default: { const _n: never = event; return state; }
    }
  },
};
