```typescript
export type FulfilmentState =
  | { status: "new"; id: string }
  | { status: "picked"; id: string; picker: string }
  | { status: "packed"; id: string; picker: string; packer: string }
  | { status: "dispatched"; id: string; carrier: string };

export type FulfilmentCommand =
  | { type: "pick"; picker: string }
  | { type: "pack"; packer: string }
  | { type: "dispatch"; carrier: string };

export type FulfilmentEvent =
  | { type: "OrderPicked"; picker: string }
  | { type: "OrderPacked"; packer: string }
  | { type: "OrderDispatched"; carrier: string };

export class FulfilmentError extends Error {
  constructor(public readonly code: string) { super(code); }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const fulfilmentDecider = (id: string): Decider<FulfilmentCommand, FulfilmentEvent, FulfilmentState> => ({
  initialState: { status: "new", id },
  decide(command, state) {
    switch (command.type) {
      case "pick":
        if (state.status !== "new") throw new FulfilmentError("ALREADY_PICKED");
        return [{ type: "OrderPicked", picker: command.picker }];
      case "pack":
        if (state.status !== "picked") throw new FulfilmentError("NOT_PICKED");
        return [{ type: "OrderPacked", packer: command.packer }];
      case "dispatch":
        if (state.status !== "packed") throw new FulfilmentError("NOT_PACKED");
        return [{ type: "OrderDispatched", carrier: command.carrier }];
      default: { const _n: never = command; throw new FulfilmentError("UNKNOWN"); }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "OrderPicked":
        if (state.status !== "new") return state;
        return { status: "picked", id: state.id, picker: event.picker };
      case "OrderPacked":
        if (state.status !== "picked") return state;
        return { status: "packed", id: state.id, picker: state.picker, packer: event.packer };
      case "OrderDispatched":
        if (state.status !== "packed") return state;
        return { status: "dispatched", id: state.id, carrier: event.carrier };
      default: { const _n: never = event; return state; }
    }
  },
});

export function when(
  state: FulfilmentState,
  event: FulfilmentEvent,
  id: string,
): FulfilmentState {
  return fulfilmentDecider(id).evolve(state, event);
}

export function aggregateStream<A, E>(
  events: E[],
  reducer: (state: A, event: E) => A,
  initial: A,
): A {
  return events.reduce(reducer, initial);
}
