```typescript
export type LoyaltyEvent =
  | { type: "AccountOpened"; data: { id: string; holder: string } }
  | { type: "PointsEarned"; data: { points: number } }
  | { type: "PointsRedeemed"; data: { points: number } }
  | { type: "TierPromoted"; data: { tier: "silver" | "gold" | "platinum" } };

export type LoyaltyAccount = Readonly<{
  id: string;
  holder: string;
  balance: number;
  tier: "bronze" | "silver" | "gold" | "platinum";
}>;

export function when(
  current: Partial<LoyaltyAccount>,
  event: LoyaltyEvent,
): Partial<LoyaltyAccount> {
  switch (event.type) {
    case "AccountOpened":
      return {
        id: event.data.id,
        holder: event.data.holder,
        balance: 0,
        tier: "bronze",
      };
    case "PointsEarned":
      return { ...current, balance: (current.balance ?? 0) + event.data.points };
    case "PointsRedeemed":
      return { ...current, balance: (current.balance ?? 0) - event.data.points };
    case "TierPromoted":
      return { ...current, tier: event.data.tier };
    default: {
      const _n: never = event;
      return current;
    }
  }
}

export function aggregateStream<A, E>(
  events: E[],
  reducer: (state: Partial<A>, event: E) => Partial<A>,
  check: (state: Partial<A>) => state is A,
): A {
  const state = events.reduce<Partial<A>>(reducer, {});
  if (!check(state)) throw new Error("INVALID_AGGREGATE_STATE");
  return state;
}

export function isLoyaltyAccount(s: Partial<LoyaltyAccount>): s is LoyaltyAccount {
  return !!s.id && !!s.holder && typeof s.balance === "number" && !!s.tier;
}

export function loyaltyFrom(events: LoyaltyEvent[]): LoyaltyAccount {
  return aggregateStream(events, when, isLoyaltyAccount);
}
```

Oskar-style: a pure `when(currentState, event)` that accumulates into `Partial<Aggregate>`, then `aggregateStream` reduces the events and validates the final shape.

```typescript
export type CashRegisterEvent =
  | { type: "RegisterPlaced"; data: { id: string; workstation: string } }
  | { type: "ShiftOpened"; data: { cashierId: string; declared: number } }
  | { type: "DrawerAdjusted"; data: { delta: number } }
  | { type: "ShiftClosed"; data: { declared: number } };

export type CashRegister = Readonly<{
  id: string;
  workstation: string;
  float: number;
  currentCashierId: string | null;
}>;

export function when(
  current: Partial<CashRegister>,
  event: CashRegisterEvent,
): Partial<CashRegister> {
  switch (event.type) {
    case "RegisterPlaced":
      return {
        id: event.data.id,
        workstation: event.data.workstation,
        float: 0,
        currentCashierId: null,
      };
    case "ShiftOpened":
      return {
        ...current,
        currentCashierId: event.data.cashierId,
        float: (current.float ?? 0) + event.data.declared,
      };
    case "DrawerAdjusted":
      return { ...current, float: (current.float ?? 0) + event.data.delta };
    case "ShiftClosed":
      return { ...current, currentCashierId: null };
    default: {
      const _n: never = event;
      return current;
    }
  }
}

export function aggregateStream<A, E>(
  events: E[],
  reducer: (s: Partial<A>, e: E) => Partial<A>,
): Partial<A> {
  return events.reduce<Partial<A>>(reducer, {});
}

export function registerFrom(events: CashRegisterEvent[]): Partial<CashRegister> {
  return aggregateStream(events, when);
}
