```typescript
export type InvoiceEvent =
  | { type: "InvoiceInitiated"; data: { number: string; issuerId: string; amount: number } }
  | { type: "InvoiceIssued"; data: { at: string } }
  | { type: "InvoiceSent"; data: { via: "email" | "post" } }
  | { type: "InvoiceVoided"; data: { reason: string } };

export type InvoiceView = Readonly<{
  number: string;
  issuerId: string;
  amount: number;
  status: "initiated" | "issued" | "sent" | "void";
  issuedAt?: string;
  sentVia?: "email" | "post";
  voidReason?: string;
}>;

export function when(
  current: Partial<InvoiceView>,
  event: InvoiceEvent,
): Partial<InvoiceView> {
  switch (event.type) {
    case "InvoiceInitiated":
      return {
        number: event.data.number,
        issuerId: event.data.issuerId,
        amount: event.data.amount,
        status: "initiated",
      };
    case "InvoiceIssued":
      return { ...current, status: "issued", issuedAt: event.data.at };
    case "InvoiceSent":
      return { ...current, status: "sent", sentVia: event.data.via };
    case "InvoiceVoided":
      return { ...current, status: "void", voidReason: event.data.reason };
    default: {
      const _n: never = event;
      return current;
    }
  }
}

export function aggregateStream<V, E>(
  events: E[],
  reducer: (v: Partial<V>, e: E) => Partial<V>,
  check: (v: Partial<V>) => v is V,
): V {
  const state = events.reduce<Partial<V>>(reducer, {});
  if (!check(state)) throw new Error("VIEW_NOT_COMPLETE");
  return state;
}

function isInvoiceView(v: Partial<InvoiceView>): v is InvoiceView {
  return !!v.number && !!v.issuerId && typeof v.amount === "number" && !!v.status;
}

export function invoiceViewFrom(events: InvoiceEvent[]): InvoiceView {
  return aggregateStream(events, when, isInvoiceView);
}
```

```typescript
export type ShipmentEvent =
  | { type: "ShipmentCreated"; id: string; origin: string; destination: string }
  | { type: "ShipmentDispatched"; carrier: string; at: string }
  | { type: "ShipmentScanned"; location: string; at: string }
  | { type: "ShipmentDelivered"; at: string }
  | { type: "ShipmentAddressCorrected"; destination: string };

export type ShipmentTrackerView = Readonly<{
  id: string;
  origin: string;
  destination: string;
  carrier: string | null;
  lastLocation: string | null;
  deliveredAt: string | null;
  scanCount: number;
}>;

export const emptyView: ShipmentTrackerView = {
  id: "",
  origin: "",
  destination: "",
  carrier: null,
  lastLocation: null,
  deliveredAt: null,
  scanCount: 0,
};

export function project(
  view: ShipmentTrackerView,
  event: ShipmentEvent,
): ShipmentTrackerView {
  switch (event.type) {
    case "ShipmentCreated":
      return {
        ...emptyView,
        id: event.id,
        origin: event.origin,
        destination: event.destination,
      };
    case "ShipmentDispatched":
      return { ...view, carrier: event.carrier };
    case "ShipmentScanned":
      return { ...view, lastLocation: event.location, scanCount: view.scanCount + 1 };
    case "ShipmentDelivered":
      return { ...view, deliveredAt: event.at };
    case "ShipmentAddressCorrected":
      return { ...view, destination: event.destination };
    default: {
      const _n: never = event;
      return view;
    }
  }
}

export function shipmentViewFrom(events: ShipmentEvent[]): ShipmentTrackerView {
  return events.reduce(project, emptyView);
}
