```typescript
export type SubscriptionEvent =
  | { type: "Subscribed"; id: string; plan: string; at: string }
  | { type: "Renewed"; at: string }
  | { type: "Cancelled"; reason: string; at: string }
  | { type: "PlanChanged"; plan: string; at: string }
  | { type: "PaymentAttemptLogged"; success: boolean };

export type StatusView = Readonly<{
  id: string;
  plan: string;
  status: "active" | "cancelled";
  lastRenewedAt: string | null;
  renewalCount: number;
}>;

export const emptyView: StatusView = {
  id: "",
  plan: "",
  status: "active",
  lastRenewedAt: null,
  renewalCount: 0,
};

export function project(view: StatusView, event: SubscriptionEvent): StatusView {
  switch (event.type) {
    case "Subscribed":
      return { ...emptyView, id: event.id, plan: event.plan };
    case "Renewed":
      return { ...view, lastRenewedAt: event.at, renewalCount: view.renewalCount + 1 };
    case "Cancelled":
      return { ...view, status: "cancelled" };
    case "PlanChanged":
      return { ...view, plan: event.plan };
    case "PaymentAttemptLogged":
      return view;
    default: {
      const _n: never = event;
      return view;
    }
  }
}

export function statusFrom(events: SubscriptionEvent[]): StatusView {
  return events.reduce(project, emptyView);
}
