```typescript
export type Snapshot<S> = { version: number; state: S };

export type SubV1 = { id: string; plan: string };
export type SubV2 = { id: string; plan: string; renewals: number };
export type SubV3 = { id: string; plan: string; renewals: number; active: boolean };
export type SubV4 = { id: string; plan: string; renewals: number; status: "active" | "cancelled" };

export type CurrentSubscription = SubV4;
export const CURRENT_VERSION = 4;

export class SnapshotError extends Error {}

const v1Tov2 = (s: SubV1): SubV2 => ({ ...s, renewals: 0 });
const v2Tov3 = (s: SubV2): SubV3 => ({ ...s, active: true });
const v3Tov4 = (s: SubV3): SubV4 => ({
  id: s.id,
  plan: s.plan,
  renewals: s.renewals,
  status: s.active ? "active" : "cancelled",
});

const upgraders: Readonly<Record<number, (s: unknown) => unknown>> = {
  1: (s) => v1Tov2(s as SubV1),
  2: (s) => v2Tov3(s as SubV2),
  3: (s) => v3Tov4(s as SubV3),
};

export function upgradeSnapshot(
  snap: Snapshot<unknown>,
): Snapshot<CurrentSubscription> {
  let version = snap.version;
  let state: unknown = snap.state;
  while (version < CURRENT_VERSION) {
    const up = upgraders[version];
    if (!up) throw new SnapshotError(`NO_UPGRADER_${version}`);
    state = up(state);
    version = version + 1;
  }
  if (version !== CURRENT_VERSION) throw new SnapshotError("UPGRADE_INCOMPLETE");
  const current = state as CurrentSubscription;
  if (!current.id || !current.plan || !current.status) {
    throw new SnapshotError("SHAPE_MISMATCH");
  }
  return { version, state: current };
}
```

Store each snapshot with `{ version, state }`. On load, run upgraders in sequence until you reach CURRENT_VERSION, then assert the final shape. Never mutate the stored blob; produce a new one each step.

```typescript
export type Snapshot<S> = { version: number; state: S };

export type ReservationV1 = { id: string; guests: number };
export type ReservationV2 = { id: string; guests: number; nights: number };
export type ReservationV3 = {
  id: string;
  guests: number;
  nights: number;
  status: "pending" | "confirmed" | "cancelled";
};

export type CurrentReservation = ReservationV3;
export const CURRENT_VERSION = 3;

class UpgradeError extends Error {}

function v1Tov2(s: ReservationV1): ReservationV2 {
  return { ...s, nights: 1 };
}

function v2Tov3(s: ReservationV2): ReservationV3 {
  return { ...s, status: "pending" };
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentReservation> {
  let v = snap.version;
  let s: unknown = snap.state;
  if (v === 1) { s = v1Tov2(s as ReservationV1); v = 2; }
  if (v === 2) { s = v2Tov3(s as ReservationV2); v = 3; }
  if (v !== CURRENT_VERSION) throw new UpgradeError("UNSUPPORTED");
  const out = s as CurrentReservation;
  if (!out.id || typeof out.guests !== "number") throw new UpgradeError("SHAPE");
  return { version: v, state: out };
}
