  command: ReservationCommand,
  ctx: { streamName: string; eventStore: EventStore },
): Promise<void> {
  const { events, revision } = await ctx.eventStore.readStream(ctx.streamName);
  const state = events.reduce(evolve, initialState);
  const newEvents = decide(command, state);
  if (newEvents.length === 0) return;
  const expectedRevision: ExpectedRevision = revision ?? "no_stream";
  await ctx.eventStore.appendToStream(ctx.streamName, newEvents, { expectedRevision });
}
