```typescript
export type EventEnvelope<E> = { position: bigint; event: E };

export interface CheckpointStore {
  read(subscription: string): Promise<bigint | null>;
  write(subscription: string, position: bigint): Promise<void>;
}

export interface Batch<E> {
  events: ReadonlyArray<EventEnvelope<E>>;
  lastPosition: bigint | null;
}

export interface EventSource<E> {
  readBatch(from: bigint, size: number): Promise<Batch<E>>;
}

export interface ProjectionHandler<V, E> {
  project(view: V, event: E): V;
  persist(view: V): Promise<void>;
  load(): Promise<V>;
}

export async function runSubscription<V, E>(
  subscriptionName: string,
  source: EventSource<E>,
  checkpoints: CheckpointStore,
  handler: ProjectionHandler<V, E>,
  batchSize: number,
): Promise<void> {
  const last = await checkpoints.read(subscriptionName);
  let from: bigint = last ?? 0n;
  let view: V = await handler.load();
  while (true) {
    const batch = await source.readBatch(from, batchSize);
    if (batch.events.length === 0) return;
    for (const { position, event } of batch.events) {
      view = handler.project(view, event);
      await handler.persist(view);
      await checkpoints.write(subscriptionName, position);
      from = position + 1n;
    }
    if (batch.lastPosition === null) return;
  }
}
