export function aggregateStream<A, E>(
  events: E[],
  reducer: (s: Partial<A>, e: E) => Partial<A>,
  check: (s: Partial<A>) => s is A,
): A {
  const s = events.reduce<Partial<A>>(reducer, {});
  if (!check(s)) throw new Error("INVALID_STATE");
  return s;
}

export function stayFrom(events: GuestStayEvent[]): GuestStay {
  return aggregateStream(events, when, isGuestStay);
}
