export type CurrentEvent =
  | { type: "SubscriptionSubscribed"; version: 2; plan: string; tier: "basic" | "premium" }
  | { type: "SubscriptionRenewed"; version: 1 }
  | { type: "SubscriptionCancelled"; version: 1; reason: string };

export type RawSubscribedV1 = {
  type: "SubscriptionSubscribed";
  version: 1;
  planName: string;
};

export type RawEvent =
  | RawSubscribedV1
  | { type: "SubscriptionSubscribed"; version: 2; plan: string; tier: "basic" | "premium" }
  | { type: "SubscriptionRenewed"; version: 1 }
  | { type: "SubscriptionCancelled"; version: 1; reason: string };

export class UnknownEventError extends Error {
  constructor(public readonly received: unknown) {
    super("UNKNOWN_EVENT");
  }
}

function assertRaw(raw: unknown): asserts raw is RawEvent {
  if (typeof raw !== "object" || raw === null) throw new UnknownEventError(raw);
  const r = raw as { type?: unknown; version?: unknown };
  if (typeof r.type !== "string" || typeof r.version !== "number") {
    throw new UnknownEventError(raw);
  }
}

export function upcast(raw: unknown): CurrentEvent {
  assertRaw(raw);
  switch (raw.type) {
    case "SubscriptionSubscribed":
      if (raw.version === 1) {
        return {
          type: "SubscriptionSubscribed",
          version: 2,
          plan: raw.planName,
          tier: "basic",
        };
      }
      return raw;
    case "SubscriptionRenewed":
      return raw;
    case "SubscriptionCancelled":
      return raw;
    default: {
      const _n: never = raw;
      throw new UnknownEventError(raw);
    }
  }
}

export type SubscriptionState =
  | { status: "none" }
  | { status: "active"; plan: string; tier: "basic" | "premium"; renewals: number }
  | { status: "cancelled"; reason: string };

export function evolve(state: SubscriptionState, event: CurrentEvent): SubscriptionState {
  switch (event.type) {
    case "SubscriptionSubscribed":
      return { status: "active", plan: event.plan, tier: event.tier, renewals: 0 };
    case "SubscriptionRenewed":
      if (state.status !== "active") return state;
      return { ...state, renewals: state.renewals + 1 };
    case "SubscriptionCancelled":
      return { status: "cancelled", reason: event.reason };
    default: { const _n: never = event; return state; }
  }
}

export function aggregate(raws: unknown[]): SubscriptionState {
  return raws.map(upcast).reduce(evolve, { status: "none" } as SubscriptionState);
}
```

Upcasting runs at read time, converting raw stored events into the current shape before the aggregate ever sees them. The stream itself is never rewritten.

