export type LoyaltyEvent =
  | { type: "AccountOpened"; id: string; holder: string }
  | { type: "PointsEarned"; id: string; points: number }
  | { type: "PointsRedeemed"; id: string; points: number };

export type LoyaltyView = Readonly<{
  accounts: Readonly<Record<string, { holder: string; balance: number }>>;
}>;

export const emptyView: LoyaltyView = { accounts: {} };

export function project(view: LoyaltyView, event: LoyaltyEvent): LoyaltyView {
  switch (event.type) {
    case "AccountOpened":
      return { accounts: { ...view.accounts, [event.id]: { holder: event.holder, balance: 0 } } };
    case "PointsEarned": {
      const acc = view.accounts[event.id];
      if (!acc) return view;
      return { accounts: { ...view.accounts, [event.id]: { ...acc, balance: acc.balance + event.points } } };
    }
    case "PointsRedeemed": {
      const acc = view.accounts[event.id];
      if (!acc) return view;
      return { accounts: { ...view.accounts, [event.id]: { ...acc, balance: acc.balance - event.points } } };
    }
    default: { const _n: never = event; return view; }
  }
}

export interface Reader {
  readBatch(from: bigint, size: number): Promise<ReadonlyArray<{ revision: bigint; event: LoyaltyEvent }>>;
}

export interface Store {
  wipe(): Promise<void>;
  save(view: LoyaltyView): Promise<void>;
}

export async function rebuildLoyalty(
  reader: Reader,
  store: Store,
  options: { from: bigint; batchSize: number },
): Promise<LoyaltyView> {
  if (options.from === 0n) await store.wipe();
  let cursor: bigint = options.from;
  let view: LoyaltyView = emptyView;
  while (true) {
    const batch = await reader.readBatch(cursor, options.batchSize);
    if (batch.length === 0) break;
    for (const { revision, event } of batch) {
      view = project(view, event);
      cursor = revision + 1n;
    }
    await store.save(view);
  }
  return view;
}
