export type ReservationEvent =
  | { type: "ReservationCreated"; id: string; guests: number }
  | { type: "ReservationConfirmed"; at: string };

export type ReservationState = { status: "none" } | { status: "pending"; guests: number };
export type ReservationCommand =
  | { type: "create"; id: string; guests: number }
  | { type: "confirm"; at: string };

export class DomainError extends Error {}

export function evolve(s: ReservationState, e: ReservationEvent): ReservationState {
  switch (e.type) {
    case "ReservationCreated": return { status: "pending", guests: e.guests };
    case "ReservationConfirmed": return s;
    default: { const _n: never = e; return s; }
  }
}

export function decide(c: ReservationCommand, s: ReservationState): ReservationEvent[] {
  switch (c.type) {
    case "create":
      if (s.status !== "none") throw new DomainError("EXISTS");
      return [{ type: "ReservationCreated", id: c.id, guests: c.guests }];
    case "confirm":
      if (s.status !== "pending") throw new DomainError("NOT_PENDING");
      return [{ type: "ReservationConfirmed", at: c.at }];
    default: { const _n: never = c; throw new DomainError("UNKNOWN"); }
  }
}

export type ExpectedRevision = bigint | "no_stream";

export interface EventStore {
  readStream(s: string): Promise<{ events: ReservationEvent[]; revision: bigint | null }>;
  appendToStream(s: string, e: ReservationEvent[], o: { expectedRevision: ExpectedRevision }): Promise<bigint>;
}

export type DashboardView = Readonly<{ id: string; guests: number; status: "pending" | "confirmed" }>;

export interface ViewStore {
  getById(id: string): Promise<DashboardView | null>;
}

export async function handleCommand(
  store: EventStore,
  streamName: string,
  command: ReservationCommand,
): Promise<void> {
  // writes go through the event store; the read store is eventually consistent
  const { events, revision } = await store.readStream(streamName);
  const state = events.reduce(evolve, { status: "none" } as ReservationState);
  const produced = decide(command, state);
  if (produced.length === 0) return;
  await store.appendToStream(streamName, produced, { expectedRevision: revision ?? "no_stream" });
}

export async function queryView(viewStore: ViewStore, id: string): Promise<DashboardView | null> {
  // read side is populated asynchronously by a projection subscription
  return viewStore.getById(id);
}
