import { Effect } from "effect";

export type ReservationState = { status: "none" } | { status: "pending"; id: string; guests: number };
export type ReservationCommand =
  | { type: "create"; id: string; guests: number }
  | { type: "addGuest" };
export type ReservationEvent =
  | { type: "ReservationCreated"; id: string; guests: number }
  | { type: "GuestAdded" };

export class DomainError extends Error {}

export const initialState: ReservationState = { status: "none" };

export function evolve(s: ReservationState, e: ReservationEvent): ReservationState {
  switch (e.type) {
    case "ReservationCreated": return { status: "pending", id: e.id, guests: e.guests };
    case "GuestAdded":
      if (s.status !== "pending") return s;
      return { ...s, guests: s.guests + 1 };
    default: { const _n: never = e; return s; }
  }
}

export function decide(c: ReservationCommand, s: ReservationState): ReservationEvent[] {
  switch (c.type) {
    case "create":
      if (s.status !== "none") throw new DomainError("EXISTS");
      return [{ type: "ReservationCreated", id: c.id, guests: c.guests }];
    case "addGuest":
      if (s.status !== "pending") throw new DomainError("NOT_PENDING");
      return [{ type: "GuestAdded" }];
    default: { const _n: never = c; throw new DomainError("UNKNOWN"); }
  }
}

export type ExpectedRevision = bigint | "no_stream";

export interface EventStore {
  readStream(s: string): Promise<{ events: ReservationEvent[]; revision: bigint | null }>;
  appendToStream(s: string, e: ReservationEvent[], o: { expectedRevision: ExpectedRevision }): Promise<bigint>;
}

export const handleReservation = (
  eventStore: EventStore,
  streamName: string,
  command: ReservationCommand,
) =>
  Effect.gen(function* () {
    const { events, revision } = yield* Effect.promise(() => eventStore.readStream(streamName));
    const state = events.reduce(evolve, initialState);
    const produced = decide(command, state);
    if (produced.length === 0) return 0n;
    const expectedRevision: ExpectedRevision = revision ?? "no_stream";
    return yield* Effect.promise(() => eventStore.appendToStream(streamName, produced, { expectedRevision }));
  });
